export const subjects = ["Math", "English", "Science", "Urdu", "Islamiat", "Computer", "Art", "PT"];
export const topicStatuses = ["Not Started", "In Progress", "Completed"] as const;
export const grades = ["A+", "A", "B+", "B", "C+", "C", "D", "F"];

