    { key: "staffId", label: "Staff ID" },
    { key: "name", label: "Name" },
    { key: "designation", label: "Designation" },
    { key: "department", label: "Department" },
    {
      key: "status",
      label: "Status",
      render: (item) => <StatusBadge status={item.status} />,
    },
    { key: "joiningDate", label: "Joining Date" },
  ];

  const filters: Filter[] = [
    {
      key: "department",
      label: "Department",
      options: departments.map((d) => ({ value: d, label: d })),
    },
    {
      key: "status",
      label: "Status",
      options: staffStatuses.map((s) => ({ value: s, label: s })),
    },
  ];

  const handleDelete = () => {
    if (deleteId) {
      deleteStaff(deleteId);
      toast({ title: "Staff deleted", description: "The staff record has been removed." });
      setDeleteId(null);
    }
  };

  return (
    <ModuleLayout module="hr" navItems={hrNavItems}>
      <PageHeader
        title="Staff List"
        description="Manage all staff members"
        action={{
          label: "Add Staff",
          onClick: () => setLocation("/hr/add"),
          hidden: !canCreate(),
        }}
      />

      <DataTable
        data={staff}
        columns={columns}
        filters={filters}
        searchPlaceholder="Search by name or ID..."
        searchKeys={["name", "staffId"]}
        onView={(item) => setLocation(`/hr/profile/${item.id}`)}
        onEdit={(item) => setLocation(`/hr/edit/${item.id}`)}
        onDelete={(item) => setDeleteId(item.id)}
        canEdit={canEdit()}
        canDelete={canDelete()}
        getRowKey={(item) => item.id}
        emptyMessage="No staff found"
        exportOptions={{
          enabled: true,
          title: "Staff List",
          filename: "staff",
        }}
      />

      <AlertDialog open={!!deleteId} onOpenChange={() => setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Staff</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete this staff record? This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete}>Delete</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </ModuleLayout>
  );
}

