import { PageHeader } from "@/components/shared/page-header";
import { financeNavItems, useFinanceData } from "./finance-data";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ModuleLayout as Layout } from "@/components/layout/module-layout";
import { Button } from "@/components/ui/button";
import { FileDown, FileSpreadsheet } from "lucide-react";
import { exportToPDF, exportToExcel } from "@/lib/export-utils";
import type { Column } from "@/components/shared/data-table";

export default function FinanceReports() {
  const { accounts, vouchers } = useFinanceData();

  const totalAssets = accounts.filter((a) => a.type === "Assets").reduce((s, a) => s + a.balance, 0);
  const totalLiabilities = accounts.filter((a) => a.type === "Liabilities").reduce((s, a) => s + a.balance, 0);
  const totalIncome = accounts.filter((a) => a.type === "Income").reduce((s, a) => s + a.balance, 0);
  const totalExpenses = accounts.filter((a) => a.type === "Expense").reduce((s, a) => s + a.balance, 0);
  const netProfit = totalIncome - totalExpenses;

  const totalReceipts = vouchers.filter((v) => v.type === "Receipt").reduce((s, v) => s + v.amount, 0);
  const totalPayments = vouchers.filter((v) => v.type === "Payment").reduce((s, v) => s + v.amount, 0);

  const summaryData = [
    { item: "Total Assets", amount: totalAssets },
    { item: "Total Liabilities", amount: totalLiabilities },
    { item: "Net Worth", amount: totalAssets - totalLiabilities },
    { item: "Total Income", amount: totalIncome },
    { item: "Total Expenses", amount: totalExpenses },
    { item: "Net Profit", amount: netProfit },
  ];

  const summaryColumns: Column<typeof summaryData[0]>[] = [
    { key: "item", label: "Item" },
    { key: "amount", label: "Amount" },
  ];

  const handleExportPDF = () => {
    exportToPDF({
      title: "Financial Reports Summary",
      filename: "finance-reports",
      data: summaryData,
      columns: summaryColumns,
    });
  };

  const handleExportExcel = () => {
    exportToExcel({
      title: "Finance Reports",
      filename: "finance-reports",
      data: summaryData,
      columns: summaryColumns,
    });
  };

  return (
    <Layout module="finance" navItems={financeNavItems}>
      <div className="space-y-6">
        <PageHeader
          title="Financial Reports"
          description="Summary of financial position"
          actions={
            <div className="flex gap-2">
              <Button variant="outline" size="sm" onClick={handleExportPDF} data-testid="button-export-pdf">
                <FileDown className="w-4 h-4 mr-2" />
                PDF
              </Button>
              <Button variant="outline" size="sm" onClick={handleExportExcel} data-testid="button-export-excel">
                <FileSpreadsheet className="w-4 h-4 mr-2" />
                Excel
              </Button>
            </div>
          }
        />

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <Card>
            <CardHeader>
              <CardTitle>Balance Sheet Summary</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex justify-between py-2 border-b">
                <span>Total Assets</span>
                <span className="font-medium text-green-600 dark:text-green-400" data-testid="text-total-assets">
                  Rs. {totalAssets.toLocaleString()}
                </span>
              </div>
              <div className="flex justify-between py-2 border-b">
                <span>Total Liabilities</span>
                <span className="font-medium text-red-600 dark:text-red-400" data-testid="text-total-liabilities">
                  Rs. {totalLiabilities.toLocaleString()}
                </span>
              </div>
              <div className="flex justify-between py-2 font-semibold">
                <span>Net Worth</span>
                <span className="text-indigo-600 dark:text-indigo-400">
                  Rs. {(totalAssets - totalLiabilities).toLocaleString()}
                </span>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader>
              <CardTitle>Income Statement</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex justify-between py-2 border-b">
                <span>Total Income</span>
                <span className="font-medium text-green-600 dark:text-green-400" data-testid="text-total-income">
                  Rs. {totalIncome.toLocaleString()}
                </span>
              </div>
              <div className="flex justify-between py-2 border-b">
                <span>Total Expenses</span>
                <span className="font-medium text-red-600 dark:text-red-400" data-testid="text-total-expenses">
                  Rs. {totalExpenses.toLocaleString()}
                </span>
              </div>
              <div className="flex justify-between py-2 font-semibold">
                <span>Net Profit</span>
                <span className={netProfit >= 0 ? "text-green-600 dark:text-green-400" : "text-red-600 dark:text-red-400"}>
                  Rs. {netProfit.toLocaleString()}
                </span>
              </div>
            </CardContent>
          </Card>
        </div>

        <Card>
          <CardHeader>
            <CardTitle>Cash Flow Summary</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="text-center p-4 bg-muted/50 rounded-lg">
                <div className="text-sm text-muted-foreground mb-1">Total Receipts</div>
                <div className="text-2xl font-bold text-green-600 dark:text-green-400">
                  Rs. {totalReceipts.toLocaleString()}
                </div>
              </div>
              <div className="text-center p-4 bg-muted/50 rounded-lg">
                <div className="text-sm text-muted-foreground mb-1">Total Payments</div>
                <div className="text-2xl font-bold text-red-600 dark:text-red-400">
                  Rs. {totalPayments.toLocaleString()}
                </div>
              </div>
              <div className="text-center p-4 bg-muted/50 rounded-lg">
                <div className="text-sm text-muted-foreground mb-1">Net Cash Flow</div>
                <div className="text-2xl font-bold text-indigo-600 dark:text-indigo-400">
                  Rs. {(totalReceipts - totalPayments).toLocaleString()}
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </Layout>
  );
}

