import { ModuleLayout } from "@/components/layout/module-layout";
import { PageHeader } from "@/components/shared/page-header";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { timetableNavItems, classes, sections } from "./timetable-data";
import { Plus } from "lucide-react";

export default function CreateTimetable() {
  return (
    <ModuleLayout module="timetable" navItems={timetableNavItems}>
      <div className="space-y-6">
        <PageHeader
          title="Create Timetable"
          description="Create a new class timetable"
        />

        <Card>
          <CardHeader>
            <CardTitle>New Timetable</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-center py-12 space-y-4">
              <div className="w-16 h-16 mx-auto bg-muted rounded-full flex items-center justify-center">
                <Plus className="w-8 h-8 text-muted-foreground" />
              </div>
              <div>
                <h3 className="font-medium">Timetable Creation</h3>
                <p className="text-sm text-muted-foreground mt-1">
                  Select a class and section to create or edit their timetable.
                </p>
              </div>
              <div className="flex flex-wrap justify-center gap-2 pt-4">
                {classes.slice(0, 3).map((cls) =>
                  sections.slice(0, 2).map((sec) => (
                    <Button key={`${cls}-${sec}`} variant="outline" data-testid={`button-create-${cls}-${sec}`}>
                      {cls} - {sec}
                    </Button>
                  ))
                )}
              </div>
              <p className="text-xs text-muted-foreground">
                Demo mode: Timetable editing interface would be shown here
              </p>
            </div>
          </CardContent>
        </Card>
      </div>
    </ModuleLayout>
  );
}

