          <StatsCard
            title="Total Items"
            value={totalItems}
            icon={Package}
            iconColor="text-emerald-500"
          />
          <StatsCard
            title="Total Sales"
            value={totalSales}
            icon={ShoppingCart}
            iconColor="text-blue-500"
          />
          <StatsCard
            title="Total Revenue"
            value={`Rs. ${totalRevenue.toLocaleString()}`}
            icon={DollarSign}
